defmodule [PROJECT_NAME].LLM.ReqLLMClient do
  @moduledoc \"\"\"\n+  Thin, copy-pasteable ReqLLM wrapper for Phoenix/Ash projects.\n+\n+  Supports:\n+  - Single-response text generation\n+  - Streaming for LiveView/Controller SSE\n+  - Structured object generation with JSON schema\n+  - Usage/telemetry forwarding\n+\n+  Replace `[PROJECT_NAME]` with your app namespace when copying.\n+  \"\"\"\n+\n+  require Logger\n+\n+  @default_provider :openai\n+  @default_model \"gpt-4.1-mini\"\n+\n+  @doc \"\"\"\n+  Simple text call.\n+  \"\"\"\n+  def chat(prompt, opts \\\\ []) when is_binary(prompt) do\n+    messages = [\n+      %{role: :system, content: opts[:system] || \"You are a concise Elixir assistant.\"},\n+      %{role: :user, content: prompt}\n+    ]\n+\n+    ReqLLM.generate_text(\n+      provider: Keyword.get(opts, :provider, @default_provider),\n+      model: Keyword.get(opts, :model, @default_model),\n+      messages: messages,\n+      max_output_tokens: opts[:max_tokens],\n+      temperature: opts[:temperature]\n+    )\n+  end\n+\n+  @doc \"\"\"\n+  Streaming example. Pass a `chunk_fun` that handles %ReqLLM.StreamChunk{}.\n+  Returns :ok | {:halt, term} when chunk_fun halts.\n+  \"\"\"\n+  def stream_chat(prompt, chunk_fun, opts \\\\ []) when is_function(chunk_fun, 1) do\n+    stream =\n+      ReqLLM.stream_text(\n+        provider: Keyword.get(opts, :provider, @default_provider),\n+        model: Keyword.get(opts, :model, @default_model),\n+        messages: [\n+          %{role: :system, content: opts[:system] || \"You are a concise Elixir assistant.\"},\n+          %{role: :user, content: prompt}\n+        ],\n+        max_output_tokens: opts[:max_tokens],\n+        temperature: opts[:temperature]\n+      )\n+\n+    Enum.reduce_while(stream, :ok, fn chunk, acc ->\n+      case chunk_fun.(chunk) do\n+        :cont -> {:cont, acc}\n+        {:halt, reason} -> {:halt, {:halt, reason}}\n+        other -> {:halt, other}\n+      end\n+    end)\n+  end\n+\n+  @doc \"\"\"\n+  Structured object generation using a JSON schema map.\n+  \"\"\"\n+  def generate_object(prompt, schema_map, opts \\\\ []) do\n+    ReqLLM.generate_object(\n+      provider: Keyword.get(opts, :provider, @default_provider),\n+      model: Keyword.get(opts, :model, @default_model),\n+      messages: [\n+        %{role: :system, content: opts[:system] || \"Return JSON matching the schema.\"},\n+        %{role: :user, content: prompt}\n+      ],\n+      response_schema: schema_map,\n+      max_output_tokens: opts[:max_tokens],\n+      temperature: opts[:temperature]\n+    )\n+  end\n+\n+  @doc \"\"\"\n+  Attach a lightweight telemetry listener for usage/cost accounting.\n+  Safe to call multiple times; guards against double attach.\n+  \"\"\"\n+  def ensure_usage_telemetry(handler_id \\\\ \"req-llm-usage\") do\n+    :telemetry.detach(handler_id)\n+\n+    :telemetry.attach(\n+      handler_id,\n+      [:req_llm, :token_usage],\n+      fn _event, measurements, metadata, _config ->\n+        Logger.info(\"req_llm usage\", measurements: measurements, metadata: metadata)\n+      end,\n+      nil\n+    )\n+  rescue\n+    ArgumentError -> :ok\n+  end\n+end\n+\n+# --- Phoenix controller example (SSE or JSON) ---\n+#\n+# defmodule [PROJECT_NAME]Web.LLMController do\n+#   use [PROJECT_NAME]Web, :controller\n+#   alias [PROJECT_NAME].LLM.ReqLLMClient\n+#\n+#   def chat(conn, %{\"prompt\" => prompt}) do\n+#     ReqLLMClient.ensure_usage_telemetry()\n+#\n+#     case ReqLLMClient.chat(prompt) do\n+#       {:ok, %{content: content, usage: usage}} -> json(conn, %{content: content, usage: usage})\n+#       {:error, reason} -> conn |> put_status(:bad_gateway) |> json(%{error: inspect(reason)})\n+#     end\n+#   end\n+# end\n+\n+# --- LiveView streaming example ---\n+#\n+# defmodule [PROJECT_NAME]Web.LLMStreamLive do\n+#   use [PROJECT_NAME]Web, :live_view\n+#   alias [PROJECT_NAME].LLM.ReqLLMClient\n+#\n+#   def mount(_params, _session, socket), do: {:ok, assign(socket, :content, \"\")}\n+#\n+#   def handle_event(\"ask\", %{\"prompt\" => prompt}, socket) do\n+#     ReqLLMClient.ensure_usage_telemetry()\n+#\n+#     ReqLLMClient.stream_chat(prompt, fn chunk ->\n+#       case chunk.type do\n+#         :content ->\n+#           send(self(), {:append, chunk.data})\n+#           :cont\n+#         :tool_call ->\n+#           # handle tool calls if you expose any\n+#           :cont\n+#         :meta -> :cont\n+#         _ -> :cont\n+#       end\n+#     end)\n+#\n+#     {:noreply, socket}\n+#   end\n+#\n+#   def handle_info({:append, delta}, socket) do\n+#     {:noreply, update(socket, :content, &(&1 <> delta))}\n+#   end\n+# end\n*** End Patch
